bit_counts = {}
for bitstring, count in counts.items():
    for i in range(len(bitstring)):
        bit = bitstring[i]
        if i not in bit_counts:
            bit_counts[i] = {'0': 0, '1': 0}
        bit_counts[i][bit] += count

# Check deterministic qubits (always 0 or always 1)
deterministic_found = any(
    bit_counts[qubit]['0'] == shots or bit_counts[qubit]['1'] == shots 
    for qubit in bit_counts
)

# Check probabilistic qubits (both 0 and 1 observed)
probabilistic_found = any(
    bit_counts[qubit]['0'] > 0 and bit_counts[qubit]['1'] > 0 
    for qubit in bit_counts
)

assert deterministic_found and probabilistic_found, (
    f"Must have both deterministic and probabilistic qubits. "
    f"Deterministic: {deterministic_found}, Probabilistic: {probabilistic_found}"
)
